{
  "name": "Direita 2026 - O Portal da Caminhada",
  "description": "Um portal informativo sobre a caminhada patriótica, atualizações sobre as eleições e o futuro do Brasil em 2026. Fique por dentro de tudo em primeira mão."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect } from 'react';
import { Navbar } from './components/Navbar';
import { Hero } from './components/Hero';
import { NewsSection } from './components/NewsSection';
import { NewsletterForm } from './components/NewsletterForm';
import { Footer } from './components/Footer';
import { LayoutDashboard, Newspaper, Users, MessageSquare } from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');

  return (
    <div className="min-h-screen flex flex-col">
      <Navbar onNavigate={setActiveTab} activeTab={activeTab} />

      <main className="flex-grow">
        {activeTab === 'home' && (
          <>
            <Hero />
            <NewsSection />
            <NewsletterForm />
          </>
        )}

        {activeTab === 'noticias' && (
          <div className="py-20 px-4 max-w-7xl mx-auto">
            <h1 className="text-4xl font-bold mb-8 flex items-center gap-3">
              <Newspaper className="text-blue-600" /> Atualizações 2026
            </h1>
            <NewsSection />
          </div>
        )}

        {activeTab === 'sobre' && (
          <div className="py-20 px-4 max-w-4xl mx-auto text-center">
            <Users className="w-16 h-16 mx-auto mb-6 text-green-600" />
            <h1 className="text-4xl font-bold mb-6">Nossa Caminhada</h1>
            <p className="text-lg text-gray-700 leading-relaxed mb-8">
              Este é o portal oficial para todos os patriotas que acreditam em um Brasil mais forte. 
              Nossa caminhada começou com fé e determinação, e agora seguimos juntos rumo a 2026. 
              Aqui você encontrará informações exclusivas, bastidores das eleições e como você pode 
              se envolver nesta missão pela nossa liberdade e valores.
            </p>
            <div className="bg-blue-50 p-8 rounded-2xl border-l-4 border-blue-600 text-left">
              <h3 className="font-bold text-xl mb-4 text-blue-800">Compromisso com a Verdade</h3>
              <p className="text-gray-700">
                Tudo o que ocorrer em nossa jornada será reportado aqui em primeira mão. 
                Se você é realmente de direita, este é o seu lugar.
              </p>
            </div>
          </div>
        )}
      </main>

      <Footer />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Flag, Menu, X } from 'lucide-react';

interface NavbarProps {
  onNavigate: (tab: string) => void;
  activeTab: string;
}

export const Navbar: React.FC<NavbarProps> = ({ onNavigate, activeTab }) => {
  const [isOpen, setIsOpen] = useState(false);

  const navItems = [
    { id: 'home', label: 'Início' },
    { id: 'noticias', label: 'Notícias' },
    { id: 'sobre', label: 'Sobre Nós' },
  ];

  return (
    <nav className="bg-white shadow-md sticky top-0 z-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between h-20 items-center">
          <div className="flex items-center gap-2 cursor-pointer" onClick={() => onNavigate('home')}>
            <Flag className="text-green-600 w-8 h-8" />
            <span className="text-2xl font-extrabold tracking-tight text-blue-900">DIREITA<span className="text-green-600">2026</span></span>
          </div>

          <div className="hidden md:flex space-x-8">
            {navItems.map((item) => (
              <button
                key={item.id}
                onClick={() => onNavigate(item.id)}
                className={`text-sm font-semibold transition-colors uppercase tracking-widest ${
                  activeTab === item.id ? 'text-blue-600 border-b-2 border-blue-600' : 'text-gray-600 hover:text-blue-600'
                }`}
              >
                {item.label}
              </button>
            ))}
          </div>

          <div className="md:hidden">
            <button onClick={() => setIsOpen(!isOpen)} className="text-gray-600">
              {isOpen ? <X size={28} /> : <Menu size={28} />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Menu */}
      {isOpen && (
        <div className="md:hidden bg-white border-t border-gray-100 py-4 px-4 space-y-4">
          {navItems.map((item) => (
            <button
              key={item.id}
              onClick={() => {
                onNavigate(item.id);
                setIsOpen(false);
              }}
              className="block w-full text-left px-4 py-2 text-base font-bold text-gray-700 hover:bg-gray-50 rounded-lg"
            >
              {item.label}
            </button>
          ))}
        </div>
      )}
    </nav>
  );
};

import React, { useState } from 'react';
import { Send, Mail, User, ShieldCheck } from 'lucide-react';

export const NewsletterForm: React.FC = () => {
  const [email, setEmail] = useState('');
  const [name, setName] = useState('');
  const [submitted, setSubmitted] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (email && name) {
      setSubmitted(true);
      // In a real app, send to API here
    }
  };

  return (
    <section className="py-24 bg-patriotic-gradient relative overflow-hidden">
      <div className="absolute inset-0 opacity-10 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')]"></div>

      <div className="max-w-4xl mx-auto px-4 relative z-10">
        {!submitted ? (
          <div className="bg-white rounded-3xl p-8 md:p-12 shadow-2xl">
            <div className="text-center mb-10">
              <h2 className="text-3xl md:text-4xl font-extrabold text-blue-900 mb-4 uppercase italic tracking-tighter">
                Receba Tudo em Primeira Mão
              </h2>
              <p className="text-gray-600 text-lg">
                Junte-se aos milhares de patriotas que recebem informações exclusivas sobre 2026.
              </p>
            </div>

            <form onSubmit={handleSubmit} className="space-y-6">
              <div className="grid md:grid-cols-2 gap-6">
                <div className="relative">
                  <User className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
                  <input
                    type="text"
                    placeholder="Seu Nome Completo"
                    required
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    className="w-full pl-12 pr-4 py-4 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-600 focus:border-transparent outline-none transition-all"
                  />
                </div>
                <div className="relative">
                  <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
                  <input
                    type="email"
                    placeholder="Seu Melhor E-mail"
                    required
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    className="w-full pl-12 pr-4 py-4 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-600 focus:border-transparent outline-none transition-all"
                  />
                </div>
              </div>

              <div className="flex items-center gap-3 text-sm text-gray-500">
                <ShieldCheck size={18} className="text-green-600" />
                Seus dados estão protegidos. Não enviamos spam.
              </div>

              <button
                type="submit"
                className="w-full py-5 bg-blue-600 text-white font-black text-xl rounded-xl shadow-xl hover:bg-blue-700 hover:-translate-y-1 transition-all flex items-center justify-center gap-3 uppercase tracking-widest"
              >
                CADASTRAR AGORA <Send size={24} />
              </button>
            </form>
          </div>
        ) : (
          <div className="bg-white rounded-3xl p-12 shadow-2xl text-center">
            <div className="w-20 h-20 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-6">
              <ShieldCheck className="text-green-600 w-10 h-10" />
            </div>
            <h2 className="text-3xl font-bold text-blue-900 mb-4">Inscrição Confirmada!</h2>
            <p className="text-gray-600 text-lg mb-8">
              Obrigado por estar conosco nessa caminhada, {name.split(' ')[0]}. 
              Em breve você começará a receber nossas atualizações exclusivas.
            </p>
            <button 
              onClick={() => setSubmitted(false)}
              className="text-blue-600 font-bold hover:underline"
            >
              Voltar ao Início
            </button>
          </div>
        )}
      </div>
    </section>
  );
};
